mapper.select:
SELECT FROM clinic_ai_model m LEFT JOIN clinic_ai_provider p ON p.provider_id = m.provider_id WHERE 1 = 1
AND m.provider_id = #{providerId}
AND m.model_code LIKE CONCAT('%', #{modelCode}, '%')
AND m.model_name LIKE CONCAT('%', #{modelName}, '%')
AND m.enabled = #{enabled}
ORDER BY m.model_id DESC

